    float pic = texture(sampler_noise_hq, vUvOriginal*uAspect.xy*.25+.1*roam_cos+.1*uTime).xyz;
    float lum = lum(pic);
    float use_it = abs(lum+.2 - (0.5-roam_cos.xy*0.15));
    float LFNoise = texture(sampler_noise_hq, pic-(vUv.yx*2 + (uTime*.15)));
